import { test, expect } from '@playwright/test';

test('T001: Verificar acceso al inventario principal despu\u00e9s de login correcto', async ({ page }) => {
  // Arrange
  await page.goto('/login');
  await page.fill('input[name="username"]', 'usuario');
  await page.fill('input[name="password"]', 'contraseña');
  await page.click('button[type="submit"]');

  // Act
  await page.click('text=Inventario principal');

  // Assert
  await expect(page.locator('text=Inventario principal')).toBeVisible();
});

test('T002: Verificar acceso no autorizado al inventario principal', async ({ page }) => {
  // Arrange
  await page.goto('/inventario-principal');

  // Act
  await page.click('text=Inventario principal');

  // Assert
  await expect(page.locator('text=Acceso no autorizado')).toBeVisible();
});

test('T003: Verificar estabilidad del release al acceder al inventario principal', async ({ page }) => {
  // Arrange
  await page.goto('/login');
  await page.fill('input[name="username"]', 'usuario');
  await page.fill('input[name="password"]', 'contraseña');
  await page.click('button[type="submit"]');

  // Act
  await page.click('text=Inventario principal');

  // Assert
  await expect(page.locator('text=Inventario principal')).toBeVisible();
  await expect(page.locator('text=No se han encontrado errores')).toBeVisible();
});
